    w.write_field("c")
    w.write_bool(obj.c)
    w.end_object
  end

  def self.decode_triple14(r)
    r.begin_object
    obj = Triple14.new
    while r.has_next_field
      key = r.read_field_name
      if key == "a" then obj.a = r.read_int64; next; end
      if key == "b" then obj.b = r.read_uint64; next; end
      if key == "c" then obj.c = r.read_bool; next; end
      r.skip
    end
    r.end_object
    obj
  end
end

class Triple15
  attr_accessor :a, :b, :c

  def initialize(
    a: 0.0,
    b: nil,
    c: nil
  )
    @a = a
    @b = b
    @c = c
  end
end

module Triple15Methods
  def self.write_triple15(w, obj)
    w.begin_object(3)
    w.write_field("a")
    w.write_float64(obj.a)
    w.write_field("b")
    w.write_string(obj.b)
    w.write_field("c")
    w.write_bytes(obj.c)
    w.end_object
  end

  def self.decode_triple15(r)
    r.begin_object
    obj = Triple15.new
    while r.has_next_field
      key = r.read_field_name
      if key == "a" then obj.a = r.read_float64; next; end
      if key == "b" then obj.b = r.read_string; next; end
      if key == "c" then obj.c = r.read_bytes; next; end
      r.skip
    end
    r.end_object
    obj
  end
end

